  1	import * as React from 'react';
  2	import {
  3	  Tooltip,
  4	  Button,
  5	  ButtonVariant,
  6	  ButtonType,
  7	  GridItem,
  8	  Grid,
  9	  gridItemSpanValueShape,
 10	} from '@patternfly/react-core';
 11	import { MinusCircleIcon } from '@patternfly/react-icons/dist/esm/icons/minus-circle-icon';
 12	import { useTranslation } from 'react-i18next';
 13	import './MultiColumnField.scss';
 14	
 15	export interface RowRendererProps {
 16	  fieldName: string;
 17	  isReadOnly?: boolean;
 18	  spans: gridItemSpanValueShape[];
 19	  complexFields?: boolean[];
 20	  disableDeleteRow?: boolean;
 21	  tooltipDeleteRow?: string;
 22	  onDelete: () => void;
 23	}
 24	export interface MultiColumnFieldRowProps
 25	  extends Omit<RowRendererProps, 'fieldName'> {
 26	  name: string;
 27	  rowIndex: number;
 28	  children?: React.ReactNode;
 29	  rowRenderer?: (row: RowRendererProps) => React.ReactNode;
 30	}
 31	
 32	const DEFAULT_ROW_RENDERER = ({
 33	  fieldName,
 34	  complexFields,
 35	  children,
 36	  isReadOnly,
 37	  spans,
 38	  disableDeleteRow,
 39	  tooltipDeleteRow,
 40	  onDelete,
 41	}): React.ReactNode => {
 42	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 43	  return (
 44	    <div className="odc-multi-column-field__row" data-test={`row ${fieldName}`}>
 45	      <Grid>
 46	        {React.Children.map(children, (child: React.ReactElement, i) => {
 47	          let newProps = child.props;
 48	          if (complexFields[i]) {
 49	            newProps = { ...newProps, namePrefix: fieldName };
 50	          } else {
 51	            newProps = {
 52	              ...newProps,
 53	              name: `${fieldName}.${child.props.name}`,
 54	            };
 55	          }
 56	          return (
 57	            <GridItem span={spans[i]} key={fieldName}>
 58	              <div className="odc-multi-column-field__col">
 59	                {React.cloneElement(child, newProps)}
 60	              </div>
 61	            </GridItem>
 62	          );
 63	        })}
 64	      </Grid>
 65	      {!isReadOnly && (
 66	        <div className={'odc-multi-column-field__col--button'}>
 67	          <Tooltip content={tooltipDeleteRow || t('Remove')}>
 68	            <Button
 69	              data-test="delete-row"
 70	              aria-label={tooltipDeleteRow || t('Remove')}
 71	              variant={ButtonVariant.plain}
 72	              type={ButtonType.button}
 73	              isInline
 74	              onClick={!disableDeleteRow ? onDelete : undefined}
 75	              isAriaDisabled={disableDeleteRow}
 76	            >
 77	              <MinusCircleIcon />
 78	            </Button>
 79	          </Tooltip>
 80	        </div>
 81	      )}
 82	    </div>
 83	  );
 84	};
 85	
 86	const MultiColumnFieldRow: React.FC<MultiColumnFieldRowProps> = ({
 87	  name,
 88	  rowIndex,
 89	  onDelete,
 90	  children,
 91	  isReadOnly,
 92	  disableDeleteRow,
 93	  tooltipDeleteRow,
 94	  spans,
 95	  complexFields = [],
 96	  rowRenderer = DEFAULT_ROW_RENDERER,
 97	}) => {
 98	  const fieldName = `${name}.${rowIndex}`;
 99	  return (
100	    <>
101	      {rowRenderer({
102	        fieldName,
103	        complexFields,
104	        children,
105	        isReadOnly,
106	        spans,
107	        disableDeleteRow,
108	        tooltipDeleteRow,
109	        onDelete,
110	      })}
111	    </>
112	  );
113	};
114	
115	export default MultiColumnFieldRow;

